sql:
SELECT median_income, unemployment_rate
FROM regional_data
WHERE region_id = 1;

SELECT state_name, median_income, unemployment_rate
FROM states
WHERE region = 'West';

SELECT states.state_id, states.state_name, voting_data.voting_result
FROM states
JOIN voting_data ON states.state_id = voting_data.state_id;

SELECT voting_result, election_year
FROM voting_data
WHERE state_id = 1;

SELECT 
  (SELECT SUM(population) FROM states WHERE region = 'South') / 
  (SELECT SUM(population) FROM states) AS Population_Ratio;

SELECT voting_result 
FROM voting_data 
WHERE voting_id = 1;

SELECT COUNT(*) 
FROM regression_models 
WHERE rfr_rmse < 0.05;

SELECT s.state_name, v.voting_result
FROM states s
JOIN voting_data v ON s.state_id = v.state_id
WHERE s.unemployment_rate = (
    SELECT MAX(unemployment_rate) FROM states
);

SELECT state_name
FROM states
WHERE unemployment_rate > (SELECT AVG(unemployment_rate) FROM states);

SELECT state_name, region, unemployment_rate
FROM states
WHERE unemployment_rate > (SELECT AVG(unemployment_rate) FROM states);

external_knowledge:
- "sailing above the turbulent seas" metaphorically describes states and regions having a performance (RFR RMSE) above the average;
- "RFR RMSE" refers to the Root Relative Squared Error, a metric used to evaluate the performance of regression models;
- "linear regression models" are a type of statistical model often used for predicting continuous outcomes;

sql:
SELECT state_name, region
FROM states
WHERE poverty_rate > 10 AND gini_coefficient < 0.45;

SELECT states.state_code, states.state_name
FROM states, national_data
WHERE states.poverty_rate > national_data.us_rfr_rmse;

SELECT state_id, state_code, state_name, region, unemployment_rate
FROM states
WHERE region = 'South' AND poverty_rate > 10;

SELECT state_name, state_code
FROM states
WHERE state_id IN (SELECT state_id FROM regression_models);
